noncompliant:
targetScope = 'subscription' // Sensitive

resource roleAssignment 'Microsoft.Authorization/roleAssignments@2022-04-01' = {
  name: guid(subscription().id, 'exampleRoleAssignment')
  properties: {
    scope: subscription().id // Sensitive: grants access to all resources
  }
}

compliant:
resource roleAssignment 'Microsoft.Authorization/roleAssignments@2022-04-01' = {
  name: guid(resourceGroup().id, 'exampleRoleAssignment')
  properties: {
    scope: resourceGroup().id // Restricts access to resource group only
  }
}
